import{_ as l,o as e,c as i,ae as o}from"./chunks/framework.B9bl8Hm5.js";const _=JSON.parse('{"title":"浏览器 知识点 dd","description":"","frontmatter":{},"headers":[],"relativePath":"browser.md","filePath":"browser.md"}'),r={name:"browser.md"};function t(d,a,s,n,c,h){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="浏览器-知识点-dd" tabindex="-1">浏览器 知识点 dd <a class="header-anchor" href="#浏览器-知识点-dd" aria-label="Permalink to &quot;浏览器 知识点 dd&quot;">​</a></h1><h2 id="_1-浏览器渲染过程" tabindex="-1">1. 浏览器渲染过程 <a class="header-anchor" href="#_1-浏览器渲染过程" aria-label="Permalink to &quot;1. 浏览器渲染过程&quot;">​</a></h2><ol><li>HTML 解析：构建 DOM 树</li><li>CSS 解析：构建 CSSOM 树</li><li>渲染树构建：结合 DOM 树和 CSSOM 树</li><li>布局（Layout）：计算元素位置和大小</li><li>绘制（Paint）：将元素绘制到屏幕上</li><li>合成（Composite）：将绘制的图层合并</li></ol><h2 id="_2-重排与重绘" tabindex="-1">2. 重排与重绘 <a class="header-anchor" href="#_2-重排与重绘" aria-label="Permalink to &quot;2. 重排与重绘&quot;">​</a></h2><ul><li>重排（Reflow）：布局发生变化，需要重新计算元素位置和大小</li><li>重绘（Repaint）：元素样式发生变化，但布局不变</li><li>优化：减少重排和重绘，使用 CSS 变换代替布局操作</li></ul><h2 id="_3-浏览器缓存" tabindex="-1">3. 浏览器缓存 <a class="header-anchor" href="#_3-浏览器缓存" aria-label="Permalink to &quot;3. 浏览器缓存&quot;">​</a></h2><ul><li>强缓存：<code>Expires</code>, <code>Cache-Control</code></li><li>协商缓存：<code>Last-Modified</code>, <code>ETag</code></li><li>缓存策略：根据资源类型设置不同的缓存策略</li></ul><h2 id="_4-同源策略" tabindex="-1">4. 同源策略 <a class="header-anchor" href="#_4-同源策略" aria-label="Permalink to &quot;4. 同源策略&quot;">​</a></h2><ul><li>定义：协议、域名、端口都相同</li><li>限制：阻止不同源的页面访问彼此的资源</li><li>跨域解决方案：CORS, JSONP, 代理服务器等</li></ul><h2 id="_5-cookie、sessionstorage-和-localstorage" tabindex="-1">5. Cookie、SessionStorage 和 LocalStorage <a class="header-anchor" href="#_5-cookie、sessionstorage-和-localstorage" aria-label="Permalink to &quot;5. Cookie、SessionStorage 和 LocalStorage&quot;">​</a></h2><ul><li>Cookie：用于会话管理，大小限制 4KB，会随请求发送</li><li>SessionStorage：会话存储，关闭标签页后清除</li><li>LocalStorage：本地存储，持久化，大小限制约 5MB</li></ul><h2 id="_6-浏览器安全" tabindex="-1">6. 浏览器安全 <a class="header-anchor" href="#_6-浏览器安全" aria-label="Permalink to &quot;6. 浏览器安全&quot;">​</a></h2><ul><li>XSS（跨站脚本攻击）：注入恶意脚本</li><li>CSRF（跨站请求伪造）：利用用户身份执行未授权操作</li><li>防范措施：输入验证、输出编码、使用 CSP 等</li></ul><h2 id="_7-性能优化" tabindex="-1">7. 性能优化 <a class="header-anchor" href="#_7-性能优化" aria-label="Permalink to &quot;7. 性能优化&quot;">​</a></h2><ul><li>减少 HTTP 请求</li><li>使用 CDN</li><li>压缩资源</li><li>合理使用缓存</li><li>优化 DOM 操作</li><li>使用 Web Workers 处理耗时任务</li></ul><h2 id="_8-浏览器事件" tabindex="-1">8. 浏览器事件 <a class="header-anchor" href="#_8-浏览器事件" aria-label="Permalink to &quot;8. 浏览器事件&quot;">​</a></h2><ul><li>事件冒泡：从目标元素向上传播</li><li>事件捕获：从根元素向下传播</li><li>事件委托：利用事件冒泡，将事件处理委托给父元素</li><li>阻止事件默认行为：<code>event.preventDefault()</code></li><li>阻止事件传播：<code>event.stopPropagation()</code></li></ul>',17)])])}const S=l(r,[["render",t]]);export{_ as __pageData,S as default};
